INSERT INTO dawah_questions (category_id, slug, title, short_answer, detailed_answer, evidences, glossary_terms, sources, keywords, target_religion, status, is_approved) VALUES

((SELECT id FROM dawah_categories WHERE slug='prophethood'), 'christian-trinity-islamic-view',
'أنا مسيحي/مسيحية — كيف يرى الإسلام عقيدة التثليث؟',
'يحترم الإسلام قداسة عيسى عليه السلام في المسيحية، لكنه يرى أن التوحيد الخالص (إله واحد بلا تعدد أقانيم) هو جوهر رسالة كل الأنبياء بمن فيهم عيسى نفسه، ولا يقبل مفهوم الأقانيم الثلاثة كتوصيف لذات الله.',
'عقيدة التثليث في المسيحية (كما صاغتها المجامع الكنسية التاريخية كمجمع نيقية) تقرر أن الله ذات واحدة في ثلاثة أقانيم متمايزة: الآب والابن والروح القدس، كل أقنوم إله كامل، والثلاثة إله واحد لا ثلاثة آلهة. هذا تصور لاهوتي عميق ومعقّد يستحق أن يُعرَض بدقة قبل أي مناقشة له. الإسلام، من جهته، يقرر توحيدًا خالصًا مطلقًا: الله واحد أحد لا شريك له ولا أقنوم يشاركه ذاته، وهذا هو جوهر "لا إله إلا الله" ذاته. يرى المسلمون أن عيسى عليه السلام نبي ورسول عظيم، وُلد بمعجزة إلهية من مريم العذراء بلا أب (وهذا ما يوافق عليه المسلمون والمسيحيون معًا)، لكنه بشر مخلوق لا إله ولا ابن لله بالمعنى الحرفي، وأن دعوته الأصلية كانت لعبادة الله وحده، تمامًا كدعوة كل الأنبياء قبله. هذا اختلاف عقدي جوهري وحقيقي بين الدينين، لا يُختزَل في جملة واحدة، ونرحّب بحوار مباشر مع داعية لمن أراد تفصيلًا أعمق يراعي خلفيته المسيحية تحديدًا.',
'[{"type":"quran","ref":"المائدة: ٧٣","text":"لَّقَدْ كَفَرَ الَّذِينَ قَالُوا إِنَّ اللَّهَ ثَالِثُ ثَلَاثَةٍ ۘ وَمَا مِنْ إِلَٰهٍ إِلَّا إِلَٰهٌ وَاحِدٌ"}, {"type":"quran","ref":"مريم: ٣٠","text":"قَالَ إِنِّي عَبْدُ اللَّهِ آتَانِيَ الْكِتَابَ وَجَعَلَنِي نَبِيًّا"}]'::jsonb,
'[{"term":"الأقانيم","definition":"مصطلح لاهوتي مسيحي يشير إلى الأقانيم الثلاثة (الآب والابن والروح القدس) التي تُشكِّل الذات الإلهية الواحدة في عقيدة التثليث."}]'::jsonb,
'[]'::jsonb,
ARRAY['التثليث','عيسى عليه السلام','المسيحية'], 'christian', 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='prophethood'), 'jesus-crucifixion-islamic-view',
'أنا مسيحي/مسيحية — لماذا لا يؤمن الإسلام بصلب عيسى وفدائه للبشرية؟',
'تؤمن المسيحية بأن عيسى صُلب فعليًا ومات فداءً لخطايا البشرية ثم قام من الموت، بينما يرى الإسلام أن الله رفع عيسى إليه ولم يُقتَل ولم يُصلَب فعلًا، وأن الخلاص في الإسلام يتحقق بالتوبة المباشرة لله لا بفداء دم.',
'العقيدة المسيحية الأساسية (صلب الفداء) تقرر أن عيسى، بصفته ابن الله المتجسد، صُلب فعليًا ومات، وأن موته كفّارة تُطهِّر البشرية من خطيئة آدم الأصلية، ثم قام من الموت في اليوم الثالث. هذا الحدث مركزي جدًا في اللاهوت المسيحي ويستحق عرضًا دقيقًا كما يؤمن به المسيحيون أنفسهم. يختلف الإسلام هنا اختلافًا جوهريًا في نقطتين مترابطتين: أولًا، ينص القرآن على أن عيسى لم يُقتَل ولم يُصلَب حقيقةً، بل "شُبِّه لهم" (رفعه الله إليه بدل ذلك) — وتفاصيل كيفية هذا التشبيه ليست مفصَّلة تفصيلًا قاطعًا في النص ذاته، وتباينت اجتهادات المفسرين في تفصيلها. ثانيًا، ينبني على هذا اختلاف أعمق في تصور "الخلاص" ذاته: لا يؤمن الإسلام بمفهوم "الخطيئة الأصلية" الموروثة من آدم التي تحتاج فداء دمٍ يُكفِّرها، بل يرى أن كل نفس تُحاسَب على عملها الخاص، وأن باب التوبة المباشرة لله مفتوح لكل إنسان بلا وسيط أو فداء. هذا فارق عقدي جوهري يستحق تفصيلًا يراعي خلفيتك المسيحية تحديدًا، ونرحّب بحوار مباشر مع داعية لمن أراد ذلك.',
'[{"type":"quran","ref":"النساء: ١٥٧","text":"وَمَا قَتَلُوهُ وَمَا صَلَبُوهُ وَلَٰكِن شُبِّهَ لَهُمْ"}]'::jsonb,
'[{"term":"الخطيئة الأصلية","definition":"عقيدة مسيحية تقرر أن كل البشر ورثوا خطيئة آدم الأولى، وأنها تحتاج فداءً يطهّرها."}]'::jsonb,
'[]'::jsonb,
ARRAY['صلب المسيح','الفداء','المسيحية'], 'christian', 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='prophethood'), 'jewish-covenant-new-prophet',
'أنا يهودي/يهودية — لماذا يدّعي الإسلام نبوة جديدة بعد التوراة؟',
'تؤمن اليهودية بعهد أبدي خاص بين الله وبني إسرائيل عبر إبراهيم وموسى، والتوراة شريعة كاملة نهائية عند اليهودية التقليدية؛ يرى الإسلام أن محمدًا ﷺ استمرار لنفس خط النبوة التوحيدية لا نقضًا لها، موجَّهًا هذه المرة لكل البشرية لا لأمة واحدة.',
'تقرر اليهودية عهدًا خاصًا (Covenant) بين الله وبني إسرائيل، بدأ بإبراهيم واكتمل بموسى عبر التوراة والشريعة المُنزَلة على جبل سيناء، وترى غالبية التيارات اليهودية التقليدية أن هذه الشريعة كاملة ونهائية لبني إسرائيل خصوصًا. يحترم الإسلام هذا التاريخ النبوي احترامًا عميقًا: يؤمن المسلمون بإبراهيم وموسى عليهما السلام كأنبياء عظماء، وبالتوراة الأصلية ككتاب سماوي حق. الفارق الجوهري الذي يقرره الإسلام: (١) أن الوحي الإلهي لم يتوقف عند موسى، بل استمر عبر أنبياء بني إسرائيل اللاحقين ثم عيسى ثم محمدًا ﷺ. (٢) أن رسالة محمد ﷺ ليست نقضًا لرسالة موسى بل امتدادًا لها موجَّهًا هذه المرة لكل البشرية لا لبني إسرائيل حصرًا، تمامًا كما وسّع الأنبياء اللاحقون في التاريخ التوراتي نفسه رسالة من سبقهم أحيانًا. (٣) يرى الإسلام أن نصوصًا توراتية تحريفية أو تفسيرية لاحقة طرأ عليها تبديل بشري عبر قرون النقل، بخلاف القرآن المحفوظ بضمان إلهي مباشر — وهذه دعوى تحتاج نقاشًا علميًا مفصَّلًا لا حسمًا بجملة واحدة. هذا اختلاف عقدي عميق يستحق حوارًا مباشرًا مع داعية مطّلع على الخلفية اليهودية تحديدًا.',
'[{"type":"quran","ref":"آل عمران: ٨٤","text":"قُلْ آمَنَّا بِاللَّهِ وَمَا أُنزِلَ عَلَيْنَا وَمَا أُنزِلَ عَلَىٰ إِبْرَاهِيمَ وَإِسْمَاعِيلَ وَإِسْحَاقَ وَيَعْقُوبَ وَالْأَسْبَاطِ وَمَا أُوتِيَ مُوسَىٰ وَعِيسَىٰ وَالنَّبِيُّونَ مِن رَّبِّهِمْ"}]'::jsonb,
'[{"term":"العهد (Covenant)","definition":"مفهوم مركزي في اليهودية يشير إلى العلاقة الخاصة الملزمة بين الله وبني إسرائيل، بدأت بإبراهيم وتجدّدت مع موسى."}]'::jsonb,
'[]'::jsonb,
ARRAY['اليهودية','العهد','نبوة محمد'], 'jewish', 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='god-existence'), 'hindu-concept-of-god-islamic-view',
'أنا هندوسي/هندوسية — كيف يرى الإسلام تعدد المظاهر الإلهية في الهندوسية؟',
'الهندوسية تقليد متنوع جدًا داخليًا: بعض مدارسها الفلسفية (كالأدفيتا فيدانتا) توحيدية أو أحادية الوجود بمعنى فلسفي عميق (برahman حقيقة مطلقة واحدة)، بينما تُمارَس شعائريًا عبادة آلهة ومظاهر متعددة تُفهَم غالبًا كتجليات لتلك الحقيقة الواحدة؛ يرى الإسلام أن التوحيد الخالص المباشر بلا وسائط أو تجليات هو جوهر الدين الصحيح.',
'من الأمانة العلمية أولًا الإقرار بأن الهندوسية ليست عقيدة واحدة موحَّدة، بل تقليد ديني وفلسفي هائل التنوع امتد آلاف السنين، يضم مدارس مختلفة جدًا: بعضها (كمدرسة الأدفيتا فيدانتا الفلسفية) تعلّم أن هناك حقيقة مطلقة واحدة فقط (تُسمى Brahman) وأن الآلهة المتعددة المعبودة شعائريًا (كفيشنو وشيفا وغيرهما) هي مظاهر أو تجليات مختلفة لهذه الحقيقة الواحدة، وهذا قريب فلسفيًا من نوع من الوحدانية الفلسفية. بينما تُمارَس الهندوسية شعائريًا لدى كثير من أتباعها عبر عبادة آلهة متعددة بأسماء وصور وقصص مستقلة نسبيًا. يرى الإسلام، من جهته، توحيدًا خالصًا مباشرًا: إله واحد بلا صورة ولا تجسيد ولا تجلٍّ بشري أو حيواني، يُعبَد مباشرة بلا وساطة أي مظهر أو رمز. هذا اختلاف جوهري بين تصورين مختلفين تمامًا لطبيعة الألوهية والعبادة، ويستحق حوارًا هادئًا يراعي التنوع الداخلي الحقيقي للتقليد الهندوسي لا اختزاله في صورة واحدة مبسَّطة، ونرحّب بتواصل مباشر مع داعية لمن أراد تفصيلًا أعمق.',
'[{"type":"quran","ref":"الإخلاص: ١-٤","text":"قُلْ هُوَ اللَّهُ أَحَدٌ * اللَّهُ الصَّمَدُ * لَمْ يَلِدْ وَلَمْ يُولَدْ * وَلَمْ يَكُن لَّهُ كُفُوًا أَحَدٌ"}]'::jsonb,
'[{"term":"Brahman","definition":"مصطلح في الفلسفة الهندوسية (خصوصًا مدرسة الأدفيتا فيدانتا) يشير إلى الحقيقة المطلقة الواحدة التي تُعتبر أساس كل الوجود."}]'::jsonb,
'[]'::jsonb,
ARRAY['الهندوسية','التوحيد','تعدد المظاهر الإلهية'], 'hindu', 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='god-existence'), 'buddhist-no-creator-islamic-view',
'أنا بوذي/بوذية ولا أومن بإله خالق — كيف يخاطبني الإسلام؟',
'البوذية التقليدية (خصوصًا الثيرافادا) لا تتمحور حول إله خالق أصلًا، بل حول تحرر النفس من المعاناة عبر النبل الرباعي والطريق الثماني؛ يقدّم الإسلام تصورًا مختلفًا جوهريًا يضع الإيمان بخالق واحد أساسًا للمعنى والغاية، لكنه يخاطب أيضًا سعيك للتحرر من المعاناة بإجابات من زاوية مختلفة.',
'من المهم الإقرار بدقة بأن البوذية، في صورتها الكلاسيكية (خصوصًا تقليد الثيرافادا)، ليست عقيدة تتمحور حول إله خالق كما في الأديان الإبراهيمية أصلًا؛ تركيزها الأساسي على "النبل الرباعي" (الحياة معاناة، للمعاناة سبب، للمعاناة نهاية، وطريق يوصل لتلك النهاية عبر "الطريق الثماني النبيل")، وتحرر النفس من دورة المعاناة والتعلق (وأحيانًا من دورة إعادة الميلاد سامسارا) بجهد فردي وممارسة تأملية، لا بعلاقة مع خالق يُعبَد. بعض المدارس البوذية اللاحقة (كالبوذية الماهايانا) طوّرت تصورات أقرب لمفاهيم شبه إلهية لبعض الكيانات (البوديساتفا)، لكنها تختلف جوهريًا عن مفهوم "الإله الخالق" التوحيدي. يقدّم الإسلام إجابة من زاوية مختلفة جذريًا: يرى أن المعاناة والاضطراب النفسي يجدان سكينتهما الحقيقية في علاقة مباشرة بخالق واحد رحيم يُدعى ويُتوكَّل عليه، لا في جهد فردي منعزل عن أي كائن أعلى. هذا اختلاف في الإطار الفلسفي الكلي لا نقطة جزئية، ويستحق حوارًا هادئًا يحترم عمق التقليد البوذي وتنوّعه الداخلي، ونرحّب بتواصل مباشر مع داعية مطّلع لمن أراد تفصيلًا أعمق.',
'[]'::jsonb,
'[{"term":"النبل الرباعي","definition":"أساس التعليم البوذي: الحياة معاناة (دوكّا)، للمعاناة سبب، يمكن إنهاء المعاناة، وهناك طريق (الطريق الثماني النبيل) يوصل لذلك."}]'::jsonb,
'[]'::jsonb,
ARRAY['البوذية','الإله الخالق','النبل الرباعي'], 'buddhist', 'draft', false)
